package edu.rice.comp322;

import edu.rice.hj.api.SuspendableException;

import static edu.rice.hj.Module0.finish;
import static edu.rice.hj.Module1.async;
import static edu.rice.hj.Module1.doWork;

/**
 * A scorer that works in parallel and maximizes ideal parallelism.
 */
public class IdealParScoring extends AbstractPreallocatedSorting {

    /**
     * <p>main.</p> Takes the names of two files, and in parallel calculates the sequence aligment scores of the two DNA
     * strands that they represent.
     *
     * @param args The names of two files.
     */
    public static void main(final String[] args) throws Exception {
        final ScoringRunner scoringRunner = new ScoringRunner(IdealParScoring::new);
        scoringRunner.start("IdealParScoring", args);
    }

    /**
     * Creates a new IdealParScoring.
     *
     * @param xLength length of the first sequence
     * @param yLength length of the second sequence
     */
    public IdealParScoring(final int xLength, final int yLength) {
        super(xLength, yLength);
    }

    /**
     * This method should be filled in with a parallel implementation of the Smith-Waterman alignment algorithm that
     * maximizes ideal parallelism.
     * {@inheritDoc}
     */
    public int scoreSequences(final String x, final String y) throws SuspendableException {
        final int xLen = getXLength();
        final int yLen = getYLength();
        final int[][] s = getMatrix();

        // Process anti-diagonals d = 2 .. xLen+yLen.
        // Diagonal d: cells (i, j) where i+j = d, i in [max(1,d-yLen), min(xLen,d-1)].
        // Within each diagonal, all cells are independent and run in parallel via async.
        // CPL = number of diagonals = xLen + yLen - 1.
        // Work = xLen * yLen (one doWork(1) per cell).
        for (int d = 2; d <= xLen + yLen; d++) {
            final int diagD = d;
            final int iStart = Math.max(1, d - yLen);
            final int iEnd = Math.min(xLen, d - 1);
            finish(() -> {
                for (int i = iStart; i <= iEnd; i++) {
                    final int ii = i;
                    final int jj = diagD - i;
                    async(() -> {
                        doWork(1);
                        final char xChar = x.charAt(ii - 1);
                        final char yChar = y.charAt(jj - 1);
                        final int diagScore = s[ii - 1][jj - 1] + getScore(charMap(xChar), charMap(yChar));
                        final int topScore = s[ii - 1][jj] + getScore(charMap(xChar), 0);
                        final int leftScore = s[ii][jj - 1] + getScore(0, charMap(yChar));
                        s[ii][jj] = Math.max(diagScore, Math.max(topScore, leftScore));
                    });
                }
            });
        }

        return s[xLen][yLen];
    }

}

package edu.rice.comp322;

import edu.rice.hj.api.SuspendableException;

import static edu.rice.hj.Module0.finish;
import static edu.rice.hj.Module0.numWorkerThreads;
import static edu.rice.hj.Module1.async;

/**
 * A scorer that allocates memory during computation, so that it may compute the scores for two sequences without
 * requiring O(|X||Y|) memory.
 */
public class SparseParScoring extends AbstractDnaScoring {

    /**
     * <p>main.</p> Takes the names of two files, and in parallel calculates the sequence aligment scores of the two DNA
     * strands that they represent.
     *
     * @param args The names of two files.
     */
    public static void main(final String[] args) throws Exception {
        final ScoringRunner scoringRunner = new ScoringRunner(SparseParScoring::new);
        scoringRunner.start("SparseParScoring", args);
    }

    /**
     * Length of the first sequence.
     */
    private final int xLength;

    /**
     * Length of the second sequence.
     */
    private final int yLength;

    /**
     * Creates a new SparseParScoring.
     *
     * @param xLength length of the first sequence
     * @param yLength length of the second sequence
     */
    public SparseParScoring(final int xLength, final int yLength) {
        if (xLength <= 0 || yLength <= 0) {
            throw new IllegalArgumentException("Lengths (" + xLength + ", " + yLength + ") must be positive!");
        }
        this.xLength = xLength;
        this.yLength = yLength;
    }

    /**
     * Here you should implement a parallel version of the SW alignment algorithm that can support datasets where the
     * size of the S matrix exceeds the available memory.
     * {@inheritDoc}
     */
    public int scoreSequences(final String x, final String y) throws SuspendableException {
        final int xLen = xLength;
        final int yLen = yLength;
        final int numTasks = numWorkerThreads();

        // Rolling arrays store only interior cells (i >= 1, j >= 1) of each anti-diagonal.
        // Diagonal d: interior i in [iStart(d), iEnd(d)] where
        //   iStart(d) = max(1, d - yLen), iEnd(d) = min(xLen, d - 1).
        // Max interior width = min(xLen, yLen).
        final int maxWidth = Math.min(xLen, yLen);
        int[] ppDiag = new int[maxWidth]; // interior of diagonal d-2
        int[] pDiag = new int[maxWidth];  // interior of diagonal d-1
        int[] cDiag = new int[maxWidth];  // interior of current diagonal d

        // Boundary helpers (computed on the fly, no storage needed):
        //   S[0][j] = j * getScore(0, 1)
        //   S[i][0] = i * getScore(1, 0)
        final int gapY = getScore(0, 1); // M['-'][char] = -2
        final int gapX = getScore(1, 0); // M[char]['-'] = -4

        for (int d = 2; d <= xLen + yLen; d++) {
            final int iStart = Math.max(1, d - yLen);
            final int iEnd = Math.min(xLen, d - 1);
            final int width = iEnd - iStart + 1;
            // iStart of diagonal d-1 and d-2 (for index lookups in rolling arrays)
            final int prevStart = Math.max(1, d - 1 - yLen);
            final int prevPrevStart = Math.max(1, d - 2 - yLen);

            final int tasks = Math.min(numTasks, width);
            final int chunkSize = (width + tasks - 1) / tasks;

            final int[] currArr = cDiag;
            final int[] prevArr = pDiag;
            final int[] prevPrevArr = ppDiag;

            final int fD = d;
            final int fIStart = iStart;
            final int fIEnd = iEnd;

            finish(() -> {
                for (int t = 0; t < tasks; t++) {
                    final int chunkBegin = fIStart + t * chunkSize;
                    final int chunkEnd = Math.min(chunkBegin + chunkSize, fIEnd + 1);
                    async(() -> {
                        for (int i = chunkBegin; i < chunkEnd; i++) {
                            final int j = fD - i;
                            final char xChar = x.charAt(i - 1);
                            final char yChar = y.charAt(j - 1);

                            // Fetch S[i-1][j-1] (diagonal d-2)
                            final int diagVal;
                            if (i - 1 == 0 && j - 1 == 0) {
                                diagVal = 0;
                            } else if (i - 1 == 0) {
                                diagVal = (j - 1) * gapY;
                            } else if (j - 1 == 0) {
                                diagVal = (i - 1) * gapX;
                            } else {
                                diagVal = prevPrevArr[(i - 1) - prevPrevStart];
                            }

                            // Fetch S[i-1][j] (diagonal d-1)
                            final int topVal;
                            if (i - 1 == 0) {
                                topVal = j * gapY;
                            } else {
                                topVal = prevArr[(i - 1) - prevStart];
                            }

                            // Fetch S[i][j-1] (diagonal d-1)
                            final int leftVal;
                            if (j - 1 == 0) {
                                leftVal = i * gapX;
                            } else {
                                leftVal = prevArr[i - prevStart];
                            }

                            final int diagScore = diagVal + getScore(charMap(xChar), charMap(yChar));
                            final int topScore = topVal + getScore(charMap(xChar), 0);
                            final int leftScore = leftVal + getScore(0, charMap(yChar));
                            currArr[i - fIStart] = Math.max(diagScore, Math.max(topScore, leftScore));
                        }
                    });
                }
            });

            // Rotate rolling arrays
            final int[] temp = ppDiag;
            ppDiag = pDiag;
            pDiag = cDiag;
            cDiag = temp;
        }

        // S[xLen][yLen] is the only cell on the last diagonal (d = xLen + yLen).
        // After the last iteration's rotation, pDiag holds the last diagonal.
        // iStart of last diagonal = max(1, xLen+yLen - yLen) = xLen.
        // Index of S[xLen][yLen] = xLen - xLen = 0.
        return pDiag[0];
    }

}

