            final int chunkSize = (width + tasks - 1) / tasks;
            finish(() -> {
                for (int t = 0; t < tasks; t++) {
                    final int chunkBegin = iStart + t * chunkSize;
                    final int chunkEnd = Math.min(chunkBegin + chunkSize, iEnd + 1);
                    async(() -> {
                        for (int i = chunkBegin; i < chunkEnd; i++) {
                            final int j = diagD - i;
                            final char xChar = x.charAt(i - 1);
                            final char yChar = y.charAt(j - 1);
                            final int diagScore = s[i - 1][j - 1] + getScore(charMap(xChar), charMap(yChar));
                            final int topScore = s[i - 1][j] + getScore(charMap(xChar), 0);
                            final int leftScore = s[i][j - 1] + getScore(0, charMap(yChar));
                            s[i][j] = Math.max(diagScore, Math.max(topScore, leftScore));
                        }
                    });
                }
            });
        }

        return s[xLen][yLen];
    }

}

